/**
 * model-viewer プレースホルダー (CSP対策で同梱必須)。
 *
 * 実際の 3D プレビューを有効化するには以下のいずれかを実行:
 *   1. npm i @google/model-viewer して dist/model-viewer.min.js をこのファイルに上書き
 *   2. https://unpkg.com/@google/model-viewer/dist/model-viewer.min.js を保存
 *
 * このプレースホルダーは <model-viewer> を「プレビュー無効」のメッセージにフォールバックさせる。
 */
class ModelViewerFallback extends HTMLElement {
  connectedCallback() {
    if (this._inited) return;
    this._inited = true;
    const src = this.getAttribute("src") || "";
    this.style.display = "flex";
    this.style.alignItems = "center";
    this.style.justifyContent = "center";
    this.style.color = "#aaa";
    this.style.fontSize = "12px";
    this.style.textAlign = "center";
    this.style.padding = "10px";
    this.innerHTML = src
      ? `3Dプレビュー (${src.split('/').pop()})<br><span style="font-size:10px">model-viewer.min.js を導入すると実プレビュー表示</span>`
      : "プレビュー無効";
  }
}
if (!customElements.get("model-viewer")) {
  customElements.define("model-viewer", ModelViewerFallback);
}
